    const males = registrationList.filter(r => r.gender === '男');
    const females = registrationList.filter(r => r.gender === '女');

    // Checked In Gender Counts
    const checkedInMales = queue.filter(t => registrationList.find(r => r.id === t.staffId)?.gender === '男').length;
    const checkedInFemales = queue.filter(t => registrationList.find(r => r.id === t.staffId)?.gender === '女').length;

    const maleRate = males.length > 0 ? Math.round((checkedInMales / males.length) * 100) : 0;
